{
  "name": "Senior Advocate Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific statewide income limits identified; local programs like McMinn Senior Activity Center target economically disadvantaged older adults who do not qualify for other assistance due to financial reasons or age restrictions[5]. Legal Assistance for the Elderly requires age 60+ with no income test mentioned[3][8].",
    "asset_limits": "No asset limits specified in search results for this program[1][3][5].",
    "other_requirements": ["Must be 60 years or older[3][5][8]", "Personally contact program office to request help (may be waived in emergencies)[3]", "Priority for cases involving imminent harm or death[3]", "Economically disadvantaged or falling into assistance 'gap' for local programs like Senior Safe at Home[5]"]
  },
  "benefits": {
    "type": "advocacy",
    "value": "Dedicated staff help navigating red tape, accessing food, home repairs, safety assistance via Senior Safe at Home (up to 25% of unmet financial needs in gap areas); legal assistance and referrals for those 60+; partnerships with housing, VA, AARP, SHIP, Social Security[3][5][8]",
    "varies_by": "region"
  },
  "application": {
    "methods": ["Phone for East TN Legal Assistance: (865) 691-2551 ext 4212 or ext 4216[3]", "Email: bbowers@ethra.org or abradley@ethra.org[3]", "In-person/mail donations to ETHRA, 9111 Cross Park Drive Ste. D-100, Knoxville, TN 37923 (indicates contact point)[3]", "Contact local senior centers like McMinn Senior Activity Center in Athens, TN for grassroots advocacy[5]", "Statewide toll-free numbers via Area Agencies on Aging and Disability (AAADs) for related services[7]"],
    "processing_time": "Priority cases given immediate attention; others first-come, first-served as capacity allows[3]",
    "waitlist": "Yes, when caseload maxed; option to join waitlist or get referrals[3]",
    "forms": ["No specific forms named; organizational membership application for coalitions, but not for client services[6]"],
    "documents": ["No specific documents listed for this program; related programs require proof of identity, citizenship, medical/financial records, income statements[2]"]
  },
  "geography": {
    "statewide": false,
    "restrictions": "Primarily local or regional; e.g., East TN via ETHRA, McMinn County (Athens), Upper Cumberland, Middle TN resources[3][5][8]",
    "regional_variations": "Operated by Area Agencies on Aging and Disability (AAADs) across 9 districts with intake/screening; only 3 dedicated Senior Advocate Programs in state, one in East TN at McMinn Senior Activity Center; legal services vary by region (East TN, Upper Cumberland, Middle TN)[3][5][7][8]",
    "offices_or_providers": ["ETHRA (Knoxville)[3]", "McMinn Senior Activity Center (Athens, TN)[5]", "Upper Cumberland and Middle TN legal programs[8]"]
  },
  "official_source": "No single primary .gov URL identified; related info at tn.gov/disability-and-aging[7]",
  "gotchas": ["Not a formal statewide program with uniform rules—mostly local senior center or AAAD initiatives; people may miss that it's one of only 3 dedicated programs in TN; capacity limits lead to waitlists; must personally request services[3][5]", "Confused with professional senior advocate careers or other programs like CHOICES/TennCare which have strict income/asset limits ($2,901/mo individual in 2025, $2,000 assets)[2]", "Priority for emergencies; non-urgent on waitlist[3]"],
  "data_shape_notes": "Highly regional via 9 AAADs and local senior centers; no uniform eligibility/income test; only 3 dedicated programs in state; grassroots focus on assistance gaps rather than fixed benefits"
}

{
  "name": "OPTIONS Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No strict income eligibility requirement. Sliding fee scale applies if income exceeds Federal Poverty Guidelines; cost share required based on income level[3][6][8].",
    "asset_limits": "No asset limits mentioned[3][6].",
    "other_requirements": [
      "Tennessee resident[6][8]",
      "Needs assistance with at least 3 Activities of Daily Living (ADLs) or Instrumental Activities of Daily Living (IADLs), such as housekeeping, shopping, bathing, walking without assistance[6][8]",
      "General qualifications must be met; determined via intake assessment[5][6]"
    ]
  },
  "benefits": {
    "type": "service",
    "value": "Homemaker services, personal care, assistance with bathing, light housekeeping, home-delivered meals, case management[3][6]. Specific hours or amounts not fixed; based on assessment needs.",
    "varies_by": "not_applicable"
  },
  "application": {
    "methods": [
      "Phone: Call intake line at 1-866-836-6678[3][5][6]",
      "Prepare intake form in advance (downloadable from Area Agency on Aging websites like ETHRA)[6]"
    ],
    "processing_time": "Intake screening by phone; if eligible and slot available, case manager contacts for in-home assessment to set up services[6]. No specific timeline stated.",
    "waitlist": "Depends on slot availability; may be turned away if no slots[6].",
    "forms": ["Intake Form (download from provider websites like ETHRA.org)[6]"],
    "documents": ["Have intake form details ready: information on ADLs/IADLs, income for fee scale, medical/functional needs to speed process[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None stated; administered through Area Agencies on Aging and Disability across Tennessee[3][6]",
    "regional_variations": "Administered by regional Area Agencies (e.g., FTAAAD, ETHRA); potential differences in providers, wait times, or slot availability by agency/region[3][6]",
    "offices_or_providers": ["First Tennessee Area Agency on Aging and Disability (FTAAAD), East Tennessee Human Resource Agency (ETHRA), contact via central intake 1-866-836-6678[3][6]"]
  },
  "official_source": "https://www.ftaaad.org/options (FTAAAD) or regional AAA sites; statewide intake via 1-866-836-6678[3][6]",
  "gotchas": [
    "No income limit but sliding fee/cost share if over Federal Poverty Guidelines—many assume it's free[3][6]",
    "Requires at least 3 ADLs/IADLs deficits; functional assessment determines eligibility[6][8]",
    "Slot availability limits access; waitlists or denials common if full[6]",
    "Separate from Medicaid-funded CHOICES program (which has strict income/asset limits and nursing home level of care)[1][2]",
    "State-funded (Options) vs. federally funded Title III-B (similar services, slightly different eligibility)[3]"
  ],
  "data_shape_notes": "No income/asset test but ADL-based functional need and cost-share fees; slot-limited with regional agency administration; often paired/confused with Title III-B[3][6]"
}

{
  "name": "Aging Nutrition Program",
  "eligibility": {
    "age": 60,
    "income_limits": "No specific statewide income limits stated; contributions suggested but not required for congregate meals. Home-delivered meals assessed via intake by local AAAD case manager. Note: Separate CSFP (sometimes referenced) limited to 150% FPL in Davidson, Dyer, Shelby Counties only[2][4][6].",
    "asset_limits": "No asset limits mentioned[6].",
    "other_requirements": ["Must be 60+ for primary eligibility; spouses (any age) and sometimes disabled under 60 in senior housing eligible for congregate meals[3][6][8]", "Home-delivered: Homebound, ill/incapacitated, unable to prepare meals or access from others (assessed via intake)[3][6][9]", "Available in all 95 counties via local AAAD[6]"]
  },
  "benefits": {
    "type": "service",
    "value": "Congregate meals (1 nutritionally balanced meal weekdays at 150+ sites, plus socialization, nutrition education/counseling); home-delivered meals (noontime meal meeting 1/3 RDA, with volunteer safety check/visit) for qualified homebound[5][6][8]",
    "varies_by": "priority_tier"
  },
  "application": {
    "methods": ["Phone: Toll-free 1-866-836-6678 to contact local Area Agency on Aging and Disability (AAAD)[5][6]", "Find congregate sites via AAAD or tn.gov link (no direct URL specified)[6]", "Local AAAD for intake assessment (in-person possible via sites)[6]"],
    "processing_time": "Not specified",
    "waitlist": "Not mentioned; advance reservations required at congregate sites[5]",
    "forms": ["Intake assessment by AAAD case manager (no specific form name/number)[6]"],
    "documents": ["Not explicitly listed; prepare proof of age, residency, homebound status if applicable via assessment[6]"]
  },
  "geography": {
    "statewide": true,
    "restrictions": "Available in all 95 Tennessee counties[6]",
    "regional_variations": "Administered locally by Area Agencies on Aging and Disability (AAAD); sites, availability, reservations vary by local AAAD; e.g., Southeast TN via SETAAAD (1-866-836-6678), Nashville/Davidson specifics via social services[3][5][6]",
    "offices_or_providers": ["Local AAAD offices (contact via 1-866-836-6678); 150+ congregate sites statewide[6]"]
  },
  "official_source": "https://www.tn.gov/disability-and-aging/disability-aging-programs/aging-nutrition-program.html[6]",
  "gotchas": ["Not an entitlement; home-delivered requires case manager assessment and may have priority for highest need (e.g., homebound/greatest need)[6][9]", "Congregate often free/suggested donation only, but not guaranteed daily[5][8]", "Confused with county-limited CSFP (food boxes, 150% FPL, only Davidson/Dyer/Shelby)[2][4]", "SNAP outreach offered but separate application[6]", "Meals weekdays only, holidays excluded; advance reservations needed[5][8]"],
  "data_shape_notes": "Statewide via 13 regional AAADs with local intake/assessment; no fixed income test, priority-based for home delivery; contributions voluntary for congregate"
}
